        {
          "@type": "Question",
          "name": "What is the difference between a GIDC leasehold plot and freehold industrial land?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "A GIDC plot is held on a long term lease, commonly 99 years, so the balance sheet carries a right to use the land rather than ownership, and transfer needs GIDC approval. Freehold land is owned outright and can be sold freely. The accounting differs too: lease premium on a GIDC plot is amortised over the lease term, while freehold land is not depreciated."
          }
        },
        {
          "@type": "Question",
          "name": "Is GST payable on a GIDC industrial plot allotment?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "One time upfront premium on a long term lease of 30 years or more granted by an industrial development corporation for an industrial plot is exempt from GST under Notification 12/2017 Central Tax (Rate). Annual lease rent, transfer fees and other GIDC service charges remain taxable at 18 percent, and that GST is usually creditable if the plot is used for business."
          }
        }
